export function update(value) {
    let date = new Date();
    let hour = date.getHours();
    let minute = date.getMinutes();
    let second = date.getSeconds();
    //idk what the fuck i am doing
    let totalSeconds = (hour * 3600) + (minute * 60) + second;

    const NOON = 12 * 3600;       // 43200 seconds
    const MIDNIGHT = 24 * 3600;   // 86400 seconds
    const FADE_DURATION = 60;     // 60 second fade

    //something something fade effect
    if (totalSeconds >= (NOON - FADE_DURATION) && totalSeconds < NOON) {
        return (totalSeconds - (NOON - FADE_DURATION)) / FADE_DURATION;
    }

    if (totalSeconds >= NOON && totalSeconds < (MIDNIGHT - FADE_DURATION)) {
        return 1;
    }

    if (totalSeconds >= (MIDNIGHT - FADE_DURATION)) {
        return 1 - ((totalSeconds - (MIDNIGHT - FADE_DURATION)) / FADE_DURATION);
    }

    return 0;
}

